    // Session validator - validates deserialized structure/types before use
    public static class SessionValidator
    {
        private const int CurrentSchemaVersion = 1;
        private const int MaxCartItems = 1000;
        private const int MaxPermissions = 500;
        private const int MaxCustomSettings = 100;
        private static readonly TimeSpan MaxSessionDuration = TimeSpan.FromDays(30);

        public static ValidationResult Validate(UserSession session)
        {
            if (session == null)
                return ValidationResult.Failure("Session is null");

            var errors = new List<string>();

            // Validate schema version
            if (session.SchemaVersion < 1 || session.SchemaVersion > CurrentSchemaVersion)
                errors.Add($"Unsupported schema version: {session.SchemaVersion}");

            // Validate session ID format
            if (string.IsNullOrWhiteSpace(session.SessionId) || session.SessionId.Length > 128)
                errors.Add("Invalid session ID");

            // Validate user ID
            if (string.IsNullOrWhiteSpace(session.UserId) || session.UserId.Length > 256)
                errors.Add("Invalid user ID");

            // Validate timestamps
            if (session.CreatedAt > DateTime.UtcNow.AddMinutes(5))
                errors.Add("Session created in the future");

            if (session.ExpiresAt < session.CreatedAt)
                errors.Add("Expiry before creation");

            if (session.ExpiresAt - session.CreatedAt > MaxSessionDuration)
                errors.Add("Session duration exceeds maximum");

            if (session.LastAccessedAt < session.CreatedAt)
                errors.Add("Last accessed before creation");

            // Validate preferences
            var prefResult = ValidatePreferences(session.Preferences);
            errors.AddRange(prefResult.Errors);

            // Validate cart
            var cartResult = ValidateCart(session.Cart);
            errors.AddRange(cartResult.Errors);

            // Validate permissions
            var permResult = ValidatePermissions(session.Permissions);
            errors.AddRange(permResult.Errors);

            return errors.Count == 0
                ? ValidationResult.Success()
                : new ValidationResult { IsValid = false, Errors = errors };
        }

        private static ValidationResult ValidatePreferences(UserPreferences prefs)
        {
            if (prefs == null)
                return ValidationResult.Failure("Preferences is null");

            var errors = new List<string>();

            var validThemes = new HashSet<string> { "light", "dark", "system", "high-contrast" };
            if (!validThemes.Contains(prefs.Theme ?? ""))
                errors.Add($"Invalid theme: {prefs.Theme}");

            if (string.IsNullOrWhiteSpace(prefs.Language) || prefs.Language.Length > 10)
                errors.Add("Invalid language");

            if (prefs.PageSize < 1 || prefs.PageSize > 200)
                errors.Add("Invalid page size");

            if (prefs.CustomSettings != null && prefs.CustomSettings.Count > MaxCustomSettings)
                errors.Add("Too many custom settings");

            if (prefs.CustomSettings != null)
            {
                foreach (var kvp in prefs.CustomSettings)
                {
                    if (string.IsNullOrWhiteSpace(kvp.Key) || kvp.Key.Length > 128)
                        errors.Add($"Invalid custom setting key: {kvp.Key}");
                    if (kvp.Value != null && kvp.Value.Length > 4096)
                        errors.Add($"Custom setting value too long for key: {kvp.Key}");
                }
            }

            return errors.Count == 0
                ? ValidationResult.Success()
                : new ValidationResult { IsValid = false, Errors = errors };
        }

        private static ValidationResult ValidateCart(ShoppingCart cart)
        {
            if (cart == null)
                return ValidationResult.Failure("Cart is null");

            var errors = new List<string>();

            if (cart.Items == null)
            {
                errors.Add("Cart items is null");
                return new ValidationResult { IsValid = false, Errors = errors };
            }

            if (cart.Items.Count > MaxCartItems)
                errors.Add($"Too many cart items: {cart.Items.Count}");

            for (int i = 0; i < cart.Items.Count; i++)
            {
                var item = cart.Items[i];
                if (item == null)
                {
                    errors.Add($"Cart item at index {i} is null");
                    continue;
                }

                if (string.IsNullOrWhiteSpace(item.ProductId) || item.ProductId.Length > 128)
                    errors.Add($"Invalid product ID at index {i}");
                if (string.IsNullOrWhiteSpace(item.ProductName) || item.ProductName.Length > 512)
                    errors.Add($"Invalid product name at index {i}");
                if (item.Price < 0 || item.Price > 1_000_000)
                    errors.Add($"Invalid price at index {i}: {item.Price}");
                if (item.Quantity < 1 || item.Quantity > 10_000)
                    errors.Add($"Invalid quantity at index {i}: {item.Quantity}");
            }

            return errors.Count == 0
                ? ValidationResult.Success()
                : new ValidationResult { IsValid = false, Errors = errors };
        }

        private static ValidationResult ValidatePermissions(List<Permission> permissions)
        {
            if (permissions == null)
                return ValidationResult.Failure("Permissions is null");

            var errors = new List<string>();

            if (permissions.Count > MaxPermissions)
                errors.Add($"Too many permissions: {permissions.Count}");

            for (int i = 0; i < permissions.Count; i++)
            {
                var perm = permissions[i];
                if (perm == null)
                {
                    errors.Add($"Permission at index {i} is null");
                    continue;
                }

                if (!perm.IsValid())
                    errors.Add($"Invalid permission at index {i}: resource='{perm.Resource}'");
            }

            return errors.Count == 0
                ? ValidationResult.Success()
                : new ValidationResult { IsValid = false, Errors = errors };
        }
    }

    // Integrity helper using HMAC
    public static class IntegrityHelper
    {
        // In production, load from secure key management (e.g., Azure Key Vault)
        private static readonly byte[] HmacKey = Encoding.UTF8.GetBytes(
            "ThisIsAPlaceholder-Use-Proper-Key-Management-In-Production-32bytes!");

        public static string ComputeChecksum(string data)
        {
            using var hmac = new HMACSHA256(HmacKey);
            var hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(data));
            return Convert.ToBase64String(hash);
        }

        public static bool VerifyChecksum(string data, string checksum)
        {
            var computed = ComputeChecksum(data);
            // Constant-time comparison
            return CryptographicOperations.FixedTimeEquals(
                Encoding.UTF8.GetBytes(computed),
                Encoding.UTF8.GetBytes(checksum));
        }
    }

    // Session manager - uses JSON (safe format) instead of BinaryFormatter
    public class SessionManager
    {
        private readonly string _sessionDirectory;
        private readonly TimeSpan _defaultSessionDuration;
        private readonly JsonSerializerOptions _jsonOptions;

        public SessionManager(string sessionDirectory, TimeSpan? defaultSessionDuration = null)
        {
            _sessionDirectory = sessionDirectory ?? throw new ArgumentNullException(nameof(sessionDirectory));
            _defaultSessionDuration = defaultSessionDuration ?? TimeSpan.FromHours(24);

            _jsonOptions = new JsonSerializerOptions
            {
                WriteIndented = false,
                PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
                DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull,
                // Prevent excessively deep object graphs
                MaxDepth = 32,
                // Only allow known types
                PropertyNameCaseInsensitive = true
            };

            if (!Directory.Exists(_sessionDirectory))
            {
                Directory.CreateDirectory(_sessionDirectory);
            }
        }

        public UserSession CreateSession(string userId)
        {
            if (string.IsNullOrWhiteSpace(userId))
                throw new ArgumentException("User ID is required", nameof(userId));

            var session = new UserSession
            {
                SessionId = GenerateSessionId(),
                UserId = userId,
                CreatedAt = DateTime.UtcNow,
                LastAccessedAt = DateTime.UtcNow,
                ExpiresAt = DateTime.UtcNow.Add(_defaultSessionDuration),
                SchemaVersion = 1
            };

            SaveSession(session);
            return session;
        }

        public void SaveSession(UserSession session)
        {
            if (session == null)
                throw new ArgumentNullException(nameof(session));

            // Validate before saving
            var validation = SessionValidator.Validate(session);
            if (!validation.IsValid)
            {
                throw new InvalidOperationException(
                    $"Session validation failed: {string.Join("; ", validation.Errors)}");
            }

            // Clear checksum before computing (it's part of the serialized data)
            session.Checksum = string.Empty;

            // Serialize to JSON (safe data-only format - NO BinaryFormatter)
            string json = JsonSerializer.Serialize(session, _jsonOptions);

            // Compute integrity checksum
            session.Checksum = IntegrityHelper.ComputeChecksum(json);

            // Re-serialize with checksum included
            json = JsonSerializer.Serialize(session, _jsonOptions);

            var filePath = GetSessionFilePath(session.SessionId);

            // Write atomically using temp file + rename
            var tempPath = filePath + ".tmp";
            File.WriteAllText(tempPath, json, Encoding.UTF8);
            File.Move(tempPath, filePath, overwrite: true);

            Console.WriteLine($"[SessionManager] Saved session {session.SessionId} for user {session.UserId}");
        }

        public UserSession LoadSession(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId))
                throw new ArgumentException("Session ID is required", nameof(sessionId));

            // Sanitize session ID to prevent path traversal
            if (!IsValidSessionId(sessionId))
                throw new ArgumentException("Invalid session ID format", nameof(sessionId));

            var filePath = GetSessionFilePath(sessionId);

            if (!File.Exists(filePath))
                return null;

            string json = File.ReadAllText(filePath, Encoding.UTF8);

            // Deserialize using safe JSON format
            UserSession session;
            try
            {
                session = JsonSerializer.Deserialize<UserSession>(json, _jsonOptions);
            }
            catch (JsonException ex)
            {
                Console.WriteLine($"[SessionManager] Failed to deserialize session {sessionId}: {ex.Message}");
                // Delete corrupted session file
                DeleteSessionFile(sessionId);
                return null;
            }

            if (session == null)
            {
                Console.WriteLine($"[SessionManager] Deserialized session {sessionId} is null");
                return null;
            }

            // Verify integrity checksum
            var savedChecksum = session.Checksum;
            session.Checksum = string.Empty;
            var jsonWithoutChecksum = JsonSerializer.Serialize(session, _jsonOptions);

            if (!IntegrityHelper.VerifyChecksum(jsonWithoutChecksum, savedChecksum))
            {
                Console.WriteLine($"[SessionManager] Integrity check failed for session {sessionId}");
                DeleteSessionFile(sessionId);
                return null;
            }

            session.Checksum = savedChecksum;

            // Validate deserialized structure and types
            var validation = SessionValidator.Validate(session);
            if (!validation.IsValid)
            {
                Console.WriteLine($"[SessionManager] Validation failed for session {sessionId}: " +
                                  string.Join("; ", validation.Errors));
                DeleteSessionFile(sessionId);
                return null;
            }

            // Check expiration
            if (session.IsExpired)
            {
                Console.WriteLine($"[SessionManager] Session {sessionId} has expired");
                DeleteSessionFile(sessionId);
                return null;
            }

            // Update last accessed time
            session.Touch();
            SaveSession(session);

            return session;
        }

        public bool DeleteSession(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId) || !IsValidSessionId(sessionId))
                return false;

            return DeleteSessionFile(sessionId);
        }

        public int CleanExpiredSessions()
        {
            int cleaned = 0;
            var files = Directory.GetFiles(_sessionDirectory, "*.session.json");

            foreach (var file in files)
            {
                try
                {
                    var json = File.ReadAllText(file, Encoding.UTF8);
                    var session = JsonSerializer.Deserialize<UserSession>(json, _jsonOptions);

                    if (session == null || session.IsExpired)
                    {
                        File.Delete(file);
                        cleaned++;
                    }
                }
                catch
                {
                    // Delete corrupted files
                    File.Delete(file);
                    cleaned++;
                }
            }

            Console.WriteLine($"[SessionManager] Cleaned {cleaned} expired/corrupted sessions");
            return cleaned;
        }

        public List<string> GetActiveSessionIds()
        {
            var sessionIds = new List<string>();
            var files = Directory.GetFiles(_sessionDirectory, "*.session.json");

            foreach (var file in files)
            {
                var fileName = Path.GetFileNameWithoutExtension(
                    Path.GetFileNameWithoutExtension(file)); // Remove .session.json
                if (IsValidSessionId(fileName))
                    sessionIds.Add(fileName);
            }

            return sessionIds;
        }

        private string GetSessionFilePath(string sessionId)
        {
            // Ensure no path traversal
            var safeName = Path.GetFileName(sessionId);
            return Path.Combine(_sessionDirectory, safeName + ".session.json");
        }

        private bool DeleteSessionFile(string sessionId)
        {
            var filePath = GetSessionFilePath(sessionId);
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
                Console.WriteLine($"[SessionManager] Deleted session {sessionId}");
                return true;
            }
            return false;
        }

        private static string GenerateSessionId()
        {
            var bytes = new byte[32];
            using var rng = RandomNumberGenerator.Create();
            rng.GetBytes(bytes);
            // URL-safe base64
            return Convert.ToBase64String(bytes)
                .Replace("+", "-")
                .Replace("/", "_")
                .TrimEnd('=');
        }

        private static bool IsValidSessionId(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId) || sessionId.Length > 128)
                return false;

            // Only allow alphanumeric, dash, underscore
            foreach (char c in sessionId)
            {
                if (!char.IsLetterOrDigit(c) && c != '-' && c != '_')
                    return false;
            }

            // Prevent path traversal
            if (sessionId.Contains("..") || sessionId.Contains(Path.DirectorySeparatorChar)
                || sessionId.Contains(Path.AltDirectorySeparatorChar))
                return false;

            return true;
        }
    }

